public void testPropertyOptionMixedCases() throws Exception
{
    Properties properties = new Properties();
    properties.setProperty( "a", "Yes" );
    properties.setProperty( "c", "TRUE" );
    properties.setProperty( "e", "0" );

    Parser parser = new PosixParser();

    CommandLine cmd = parser.parse(opts, null, properties);
    assertTrue( cmd.hasOption("a") );
    assertTrue( cmd.hasOption("c") );
    assertTrue( cmd.hasOption("e") );

    properties = new Properties();
    properties.setProperty( "a", "YeS" );
    properties.setProperty( "c", "1" );
    properties.setProperty( "e", "100" );

    cmd = parser.parse(opts, null, properties);
    assertTrue( cmd.hasOption("a") );
    assertTrue( cmd.hasOption("c") );
    assertTrue( cmd.hasOption("e") );
}

public void testPropertyOptionEmptyAndNull() throws Exception
{
    Properties properties = new Properties();
    properties.setProperty( "e", "" );

    Parser parser = new PosixParser();

    CommandLine cmd = parser.parse(opts, null, properties);
    assertTrue( cmd.hasOption("e") );

    properties = new Properties();
    properties.setProperty( "a", "" );
    properties.setProperty( "c", "" );

    cmd = parser.parse(opts, null, properties);
    assertTrue( !cmd.hasOption("a") );
    assertTrue( !cmd.hasOption("c") );
}

public void testPropertyOptionMultipleProperties() throws Exception
{
    Properties properties = new Properties();
    properties.setProperty( "a", "1" );
    properties.setProperty( "c", "yes" );
    properties.setProperty( "e", "arbitrary" );

    Parser parser = new PosixParser();

    CommandLine cmd = parser.parse(opts, null, properties);
    assertTrue( cmd.hasOption("a") );
    assertTrue( cmd.hasOption("c") );
    assertTrue( cmd.hasOption("e") );

    properties = new Properties();
    properties.setProperty( "a", "maybe" );
    properties.setProperty( "c", "2" );

    cmd = parser.parse(opts, null, properties);
    assertTrue( !cmd.hasOption("a") );
    assertTrue( !cmd.hasOption("c") );
    assertTrue( !cmd.hasOption("e") );
}
